import 'package:flutter/material.dart';import 'app_colors.dart';import 'app_spacing.dart';class DsCard extends StatelessWidget {  final Widget child;  final EdgeInsets? padding;  final VoidCallback? onTap;  final bool isActive;  const DsCard({    super.key,    required this.child,    this.padding,    this.onTap,    this.isActive = false,  });  @override  Widget build(BuildContext context) {    return GestureDetector(      onTap: onTap,      child: AnimatedContainer(        duration: const Duration(milliseconds: 200),        curve: Curves.easeOut,        decoration: BoxDecoration(          color: AppColors.surface,          borderRadius: BorderRadius.circular(AppSpacing.borderRadiusMedium),          border: isActive              ? Border.all(color: AppColors.primary, width: 0.5)              : Border.all(color: Colors.transparent, width: 0.5),          boxShadow: [            BoxShadow(              color: Colors.black.withOpacity(0.25),              offset: const Offset(0, 4),              blurRadius: 12,            ),            BoxShadow(              color: Colors.black.withOpacity(0.1),              offset: const Offset(0, 1),              blurRadius: 4,            ),            BoxShadow(              color: Colors.black.withOpacity(0.2),              offset: const Offset(0, 1),              blurRadius: 2,              spreadRadius: 0,              inset: true,            ),            if (isActive)              BoxShadow(                color: AppColors.primary.withOpacity(0.3),                blurRadius: 8,                spreadRadius: 1,              ),          ],        ),        padding: padding ?? AppSpacing.cardPadding,        child: child,      ),    );  }}